import React, { useEffect, useCallback, useState } from "react"
import { useLanguage } from "../contexts/LanguageContext"
import { getText } from "./../data"
import { GatsbyImage } from "gatsby-plugin-image"
import "./../css/modal.scss" // Reuse existing modal styles

const VideoItem = ({ src }) => {
    const videoRef = React.useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (videoRef.current) {
                        if (entry.isIntersecting) {
                            videoRef.current.play().catch(e => console.warn("Auto-play failed:", e));
                        } else {
                            videoRef.current.pause();
                        }
                    }
                });
            },
            { threshold: 0.5 }
        );

        if (videoRef.current) observer.observe(videoRef.current);

        return () => {
            if (videoRef.current) observer.unobserve(videoRef.current);
        };
    }, []);

    return (
        <video
            ref={videoRef}
            src={src}
            className="img-fluid modal-media"
            muted
            loop
            playsInline
            preload="metadata"
            controls={false}
            style={{ marginBottom: '0.5rem', width: '100%', borderRadius: '8px' }}
        />
    );
};

export default function DetailedModal({ closeModal, content, title, image, caption, mediaItems }) {
    const { language } = useLanguage();
    const [isClosing, setIsClosing] = useState(false);

    // Enhanced close function with animation
    const handleClose = useCallback(() => {
        setIsClosing(true);
        // Wait for animation to complete before actually closing
        setTimeout(() => {
            closeModal(false);
        }, 300); // Match the CSS animation duration
    }, [closeModal]);

    // Keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e) => {
            if (e.key === 'Escape') {
                e.preventDefault();
                handleClose();
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => {
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [handleClose]);

    useEffect(() => {
        document.body.classList.add('modal-open');
        return () => {
            document.body.classList.remove('modal-open');
        };
    }, []);

    return (
        <>
            <div
                className={`modalBackground ${isClosing ? 'closing' : ''}`}
                onClick={handleClose}
                role="button"
                tabIndex={0}
            ></div>
            <div className={`modalContainer ${isClosing ? 'closing' : ''}`}>
                <div className="titleCloseBtn">
                    <button onClick={handleClose}>
                        <h3>&#215;</h3>
                    </button>
                </div>

                <div className="title">
                    <h1>{getText(title, language)}</h1>
                </div>

                <div className="body">
                    {(() => {
                        // Normalize media items
                        const items = mediaItems || (image ? [{
                            type: image.endsWith('.mp4') ? 'video' : 'image',
                            src: image,
                            caption: caption,
                            position: 'before'
                        }] : []);

                        const renderMediaItem = (item, index) => {
                            const isVideo = item.type === 'video' || (typeof item.src === 'string' && item.src.endsWith('.mp4'));
                            // Check if src is a gatsbyImageData object
                            const isGatsbyImage = item.src && typeof item.src === 'object' && item.src.images;

                            return (
                                <div key={index} style={{ width: '100%', marginBottom: '1rem' }}>
                                    {isVideo ? (
                                        <VideoItem src={item.src} />
                                    ) : isGatsbyImage ? (
                                        <GatsbyImage
                                            image={item.src}
                                            alt={item.caption ? getText(item.caption, language) : getText(title, language)}
                                            className="img-fluid modal-media"
                                            style={{ marginBottom: '0.5rem' }}
                                        />
                                    ) : (
                                        <img
                                            src={item.src}
                                            className="img-fluid modal-media"
                                            alt={getText(title, language)}
                                            loading="lazy"
                                            style={{ marginBottom: '0.5rem' }}
                                        />
                                    )}
                                    {item.caption && (
                                        <p style={{
                                            fontFamily: '"Montserrat", sans-serif',
                                            fontWeight: 400,
                                            fontSize: '0.85rem',
                                            color: 'var(--text-dark-secondary)',
                                            textAlign: 'center',
                                            margin: '0',
                                            lineHeight: '1.4'
                                        }}>
                                            {getText(item.caption, language)}
                                        </p>
                                    )}
                                </div>
                            );
                        };

                        const beforeItems = items.filter(item => !item.position || item.position === 'before');
                        const afterItems = items.filter(item => item.position === 'after');

                        return (
                            <>
                                {beforeItems.map(renderMediaItem)}
                                <div className="text-content" dangerouslySetInnerHTML={{ __html: getText(content, language) }} style={{ width: '100%' }} />
                                {afterItems.map(renderMediaItem)}
                            </>
                        );
                    })()}
                </div>
            </div>
        </>
    )
}
