import React, { useState, useRef, useEffect } from "react"
import Fade from "./animations/Fade"
import { useLanguage } from "../contexts/LanguageContext"
import { getText } from "../data"
import "../styles/publications.scss"

// Import publication images/videos
import eesd2 from "../images/publications/eesd_2.webp"
import eesd1 from "../images/publications/eesd_1.webm"
import patentI from "../images/publications/patent_i.webp"
import patentUm from "../images/publications/patent_um.webp"
import jrtst from "../images/publications/jrtst.webp"
import csse from "../images/publications/csse.webp"
import ntuThesis from "../images/publications/ntu_thesis.webp"

// Helper function to detect if file is a video
const isVideoFile = (url) => {
  if (!url) return false;
  const videoExtensions = ['.mp4', '.webm', '.mov', '.avi'];
  return videoExtensions.some(ext => typeof url === 'string' && url.toLowerCase().endsWith(ext));
};

const Publications = () => {
  const { language } = useLanguage();
  const [videoErrors, setVideoErrors] = useState({});
  const videoRefs = useRef([]);

  // Force video play when videos come into view (helps with iOS autoplay restrictions)
  useEffect(() => {
    try {
      const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const video = entry.target;
            try {
              forceVideoPlay(video);
            } catch (error) {
              console.warn('Error forcing video play:', error);
            }
          }
        });
      }, {
        threshold: 0.5 // Trigger when 50% of video is visible
      });

      // Observe all video elements
      videoRefs.current.forEach(video => {
        if (video) {
          try {
            observer.observe(video);
          } catch (error) {
            console.warn('Error observing video:', error);
          }
        }
      });

      return () => {
        try {
          observer.disconnect();
        } catch (error) {
          console.warn('Error disconnecting observer:', error);
        }
      };
    } catch (error) {
      console.warn('Error setting up intersection observer:', error);
    }
  }, []); // Remove the mutable dependency

  const handleVideoError = (publicationId) => {
    console.warn(`Video failed to load for publication ${publicationId}`);
    setVideoErrors(prev => ({ ...prev, [publicationId]: true }));
  };

  const forceVideoPlay = (videoElement) => {
    if (videoElement) {
      videoElement.muted = true; // Ensure it's muted for autoplay
      videoElement.loop = true;  // Ensure looping is enabled

      const playPromise = videoElement.play();

      if (playPromise !== undefined) {
        playPromise.catch((error) => {
          console.log('Autoplay failed, attempting manual play:', error);
          // Try again after a short delay
          setTimeout(() => {
            videoElement.play().catch(e => console.log('Manual play also failed:', e));
          }, 100);
        });
      }
    }
  };

  const handleVideoEnded = (videoElement) => {
    // Fallback for devices where loop attribute might not work
    if (videoElement) {
      videoElement.currentTime = 0;
      videoElement.play().catch(e => console.log('Loop restart failed:', e));
    }
  };

  const canPlayVideo = (publication) => {
    // Only show fallback if there was an actual error, not for iOS WebM incompatibility
    return !videoErrors[publication.id];
  };

  // Publication data with actual links
  const publicationsData = [
    {
      id: 0,
      title: "Seismic design and analysis of truss‐confined buckling‐restrained braces",
      subtitle: "Earthquake Engineering & Structural Dynamics, 2025",
      imageSrc: eesd2,
      type: "EESD",
      typeColor: "rgb(227, 118, 103)",
      buttons: [
        {
          text: { en: "View Publication", zh: "查看论文" },
          url: "https://onlinelibrary.wiley.com/share/author/PCEKRKFPGGNR95FSAVTX?target=10.1002/eqe.4252"
        }
      ]
    },
    {
      id: 1,
      title: "Experimental behavior of truss-confined buckling-restrained braces",
      subtitle: "Earthquake Engineering & Structural Dynamics, 2023",
      imageSrc: eesd1,
      type: "EESD",
      typeColor: "rgb(227, 118, 103)",
      buttons: [
        {
          text: { en: "View Publication", zh: "查看论文" },
          url: "https://onlinelibrary.wiley.com/share/author/CBGYT4F67VGIASGCJYJP?target=10.1002/eqe.3777"
        }
      ]
    },
    {
      id: 2,
      title: "Invention Patent: Truss-Confined Buckling-Restrained Brace",
      subtitle: "Taiwan Patent I715223 | Japan Patent JP6983857B2 | China Patent CN112575895B",
      imageSrc: patentI,
      type: "Patent",
      typeColor: "rgb(255, 183, 65)",
      buttons: [
        {
          text: { en: "Taiwan", zh: "台灣" },
          url: "https://patents.google.com/patent/TWI715223B/en"
        },
        {
          text: { en: "Japan", zh: "日本" },
          url: "https://patents.google.com/patent/JP6983857B2/en"
        },
        {
          text: { en: "China", zh: "中國" },
          url: "https://patents.google.com/patent/CN112575895B/en"
        }
      ]
    },
    {
      id: 3,
      title: "Utility Model Patent: Truss-Confined Buckling-Restrained Brace",
      subtitle: "Taiwan Patent M589208 | China Patent CN211143314U",
      imageSrc: patentUm,
      type: "Patent",
      typeColor: "rgb(255, 183, 65)",
      buttons: [
        {
          text: { en: "Taiwan", zh: "台灣" },
          url: "https://patents.google.com/patent/TWM589208U/en"
        },
        {
          text: { en: "China", zh: "中國" },
          url: "https://patents.google.com/patent/CN211143314U/en"
        }
      ]
    },
    {
      id: 4,
      title: "Taipei Twin Towers: Structural Design for Integrating High-rise and Metro Stations",
      subtitle: "Journal of Rapid Transit System and Technology, 2025",
      imageSrc: jrtst,
      type: "Journal",
      typeColor: "rgb(80, 161, 168)",
      buttons: [
        {
          text: { en: "View Publication", zh: "查看论文" },
          url: "https://ebook.dorts.gov.taipei/JRTST/ebook/no60/index.html#p=52"
        }
      ]
    },
    {
      id: 5,
      title: "Long-Span Buckling-Restrained Braces using Truss-Confined Restrainers",
      subtitle: "Structural Engineering, 2021 | Structural Engineering, 2022",
      imageSrc: csse,
      type: "Journal",
      typeColor: "rgb(80, 161, 168)",
      buttons: [
        {
          text: { en: "2021 Paper", zh: "2021 论文" },
          url: "https://doi.org/10.6849/SE.202106_36(2).0001"
        },
        {
          text: { en: "2022 Paper", zh: "2022 论文" },
          url: "https://doi.org/10.6849/SE.202209_37(3).0002"
        }
      ]
    },
    {
      id: 6,
      title: "A Study of BRBs using Steel Truss Restrainers",
      subtitle: "National Taiwan University Master's Thesis, 2020",
      imageSrc: ntuThesis,
      type: "Thesis",
      typeColor: "rgb(255, 130, 21)",
      buttons: [
        {
          text: { en: "View Publication", zh: "查看论文" },
          url: "http://tdr.lib.ntu.edu.tw/jspui/handle/123456789/61616"
        }
      ]
    }
  ];

  return (
    <div className="section" id="publications">
      <div className="container">
        <Fade bottom cascade distance="20px">
          <h1>{getText({ en: "Publications", zh: "发表论文" }, language)}</h1>
        </Fade>
        <div className="publications-wrapper">
          <div className="grid">
            <Fade bottom distance="20px">
              {publicationsData.map((publication, index) => (
                <div key={index} className="publication-card">
                  <div
                    className="background-media"
                    style={{
                      backgroundImage: publication.imageSrc && publication.imageSrc.endsWith('.gif')
                        ? `linear-gradient(to bottom, transparent 0%, transparent 50%, rgba(240, 248, 255, 0.5) 70%, rgba(240, 248, 255, 0.9) 85%, rgba(240, 248, 255, 1.0) 100%), url(${publication.imageSrc})`
                        : (isVideoFile(publication.imageSrc) ? 'none' : `url(${publication.imageSrc})`)
                    }}
                  >
                    {isVideoFile(publication.imageSrc) && canPlayVideo(publication) && (
                      <video
                        ref={el => {
                          try {
                            videoRefs.current[publication.id] = el;
                          } catch (error) {
                            console.warn(`Error setting video ref for publication ${publication.id}:`, error);
                          }
                        }}
                        className="background-video"
                        src={publication.imageSrc}
                        autoPlay
                        muted
                        loop
                        playsInline
                        preload="metadata"
                        loading="lazy"
                        controls={false}
                        disablePictureInPicture
                        onError={() => {
                          try {
                            handleVideoError(publication.id);
                          } catch (error) {
                            console.warn(`Error in video error handler for publication ${publication.id}:`, error);
                          }
                        }}
                        onLoadStart={() => {
                          try {
                            console.log(`Loading video for publication ${publication.id}`);
                          } catch (error) {
                            console.warn(`Error in video load start handler for publication ${publication.id}:`, error);
                          }
                        }}
                        onCanPlay={(e) => {
                          try {
                            console.log(`Video can play for publication ${publication.id}`);
                            forceVideoPlay(e.target);
                          } catch (error) {
                            console.warn(`Error in video can play handler for publication ${publication.id}:`, error);
                          }
                        }}
                        onLoadedData={(e) => {
                          try {
                            console.log(`Video loaded for publication ${publication.id}`);
                            forceVideoPlay(e.target);
                          } catch (error) {
                            console.warn(`Error in video loaded data handler for publication ${publication.id}:`, error);
                          }
                        }}
                        onEnded={(e) => {
                          try {
                            console.log(`Video ended for publication ${publication.id}, restarting loop`);
                            handleVideoEnded(e.target);
                          } catch (error) {
                            console.warn(`Error in video ended handler for publication ${publication.id}:`, error);
                          }
                        }}
                        style={{
                          WebkitTransform: 'translateZ(0)',
                          transform: 'translateZ(0)',
                        }}
                      />
                    )}
                    {isVideoFile(publication.imageSrc) && !canPlayVideo(publication) && (
                      <div
                        className="background-video video-fallback"
                        style={{
                          backgroundColor: '#e9ecef',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '0.9rem',
                          color: 'var(--text-dark-secondary)',
                          textAlign: 'center',
                          padding: '20px'
                        }}
                      >
                        <div>
                          🎬<br />
                          <small>Video preview not available<br />on this device</small>
                        </div>
                      </div>
                    )}
                  </div>
                  <div className="content">
                    <div
                      className="publication-type"
                      style={{ backgroundColor: publication.typeColor }}
                    >
                      {publication.type}
                    </div>
                    <h3 className="header">{publication.title}</h3>
                    <h4 className="subtitle">{publication.subtitle}</h4>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                      {publication.buttons.map((btn, btnIndex) => (
                        <button
                          key={btnIndex}
                          onClick={() => {
                            window.open(btn.url, "_blank");
                          }}
                          type="button"
                          className="btn"
                        >
                          {getText(btn.text, language)}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </Fade>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Publications